import{_ as e,o,c as l,ag as a}from"./chunks/framework-C5-Jzrz4.js";const d=JSON.parse('{"title":"请求层封装","description":"alovaInstance 请求配置、加密、响应处理与错误处理机制","frontmatter":{"title":"请求层封装","description":"alovaInstance 请求配置、加密、响应处理与错误处理机制"},"headers":[],"relativePath":"scripts/api/请求层封装.md","filePath":"scripts/api/请求层封装.md","lastUpdated":null}');const i=e({name:"scripts/api/请求层封装.md"},[["render",function(e,d,i,c,t,r){return o(),l("div",null,[...d[0]||(d[0]=[a('<h1 id="请求层封装" tabindex="-1">请求层封装 <a class="header-anchor" href="#请求层封装" aria-label="Permalink to &quot;请求层封装&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>当前项目请求层由 <code>alova + axios adapter</code> 实现，统一封装在 <code>apps/web-antd/src/utils/http/index.ts</code>。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>调整请求头、超时、加密逻辑</li><li>统一处理成功码、401、分页返回</li><li>排查接口报错弹窗与消息提示</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>apps/web-antd/src/utils/http/index.ts</code></li><li><code>apps/web-antd/src/utils/http/checkStatus.ts</code></li><li><code>apps/web-antd/src/utils/http/helper.ts</code></li><li><code>packages/constants/src/core.ts</code></li></ul><h2 id="核心机制或功能说明" tabindex="-1">核心机制或功能说明 <a class="header-anchor" href="#核心机制或功能说明" aria-label="Permalink to &quot;核心机制或功能说明&quot;">​</a></h2><h3 id="实例基础配置" tabindex="-1">实例基础配置 <a class="header-anchor" href="#实例基础配置" aria-label="Permalink to &quot;实例基础配置&quot;">​</a></h3><ul><li><code>baseURL</code>：来源于 <code>useAppConfig(...).apiURL</code></li><li><code>timeout</code>：<code>10_000</code></li><li><code>cacheFor</code>：<code>null</code>（关闭 GET 缓存）</li><li><code>shareRequest</code>：<code>false</code></li></ul><h3 id="请求前处理-beforerequest" tabindex="-1">请求前处理（<code>beforeRequest</code>） <a class="header-anchor" href="#请求前处理-beforerequest" aria-label="Permalink to &quot;请求前处理（`beforeRequest`）&quot;">​</a></h3><ul><li>合并默认 Axios 配置： <ul><li><code>successMessageMode: &#39;none&#39;</code></li><li><code>errorMessageMode: &#39;message&#39;</code></li><li><code>withToken: true</code></li><li><code>isReturnNativeResponse: false</code></li><li><code>isTransformResponse: true</code></li><li><code>encrypt: false</code></li></ul></li><li>注入头信息： <ul><li><code>Authorization: Bearer &lt;token&gt;</code></li><li><code>Accept-Language</code> / <code>Content-Language</code>（<code>zh_CN</code> 或 <code>en_US</code>）</li><li><code>ClientID</code></li></ul></li><li>GET/DELETE 参数序列化： <ul><li>默认使用 <code>stringify(params, { arrayFormat: &#39;repeat&#39; })</code></li></ul></li><li>可选加密链路（仅 POST/PUT 且 <code>encrypt: true</code>）： <ul><li>生成随机 AES key</li><li><code>encrypt-key</code> 头写入 RSA 加密后的 key</li><li>请求体 AES 加密</li><li>强制 <code>Content-Type: application/json;charset=UTF-8</code></li></ul></li></ul><h3 id="响应处理-responded-onsuccess" tabindex="-1">响应处理（<code>responded.onSuccess</code>） <a class="header-anchor" href="#响应处理-responded-onsuccess" aria-label="Permalink to &quot;响应处理（`responded.onSuccess`）&quot;">​</a></h3><ul><li>若响应头存在 <code>encrypt-key</code>，先执行 RSA + AES 解密</li><li>按 <code>BUSINESS_SUCCESS_CODE = 200</code> 判断业务成功</li><li>成功时返回值规则： <ul><li>有 <code>data</code> 字段：直接返回 <code>data</code></li><li>无 <code>data</code> 字段：返回 <code>{ rows, total, ... }</code> 等剩余字段</li></ul></li><li><code>UNAUTHORIZED_CODE = 401</code> 时执行统一登出 <code>handleUnauthorizedLogout()</code></li><li>支持 <code>isReturnNativeResponse</code>、<code>isTransformResponse</code> 控制返回形态</li></ul><h3 id="错误处理-responded-onerror" tabindex="-1">错误处理（<code>responded.onError</code>） <a class="header-anchor" href="#错误处理-responded-onerror" aria-label="Permalink to &quot;错误处理（`responded.onError`）&quot;">​</a></h3><ul><li>网络超时与网络错误优先处理</li><li>HTTP 状态码交由 <code>checkStatus</code> 映射提示： <ul><li><code>400/401/403/404/408/default</code></li></ul></li><li>登录超时流程由 <code>helper.ts</code> 的 <code>handleUnauthorizedLogout()</code> 管控</li></ul><h3 id="扩展请求方法" tabindex="-1">扩展请求方法 <a class="header-anchor" href="#扩展请求方法" aria-label="Permalink to &quot;扩展请求方法&quot;">​</a></h3><p>实例额外提供：</p><ul><li><code>getWithMsg</code></li><li><code>postWithMsg</code></li><li><code>putWithMsg</code></li><li><code>deleteWithMsg</code></li></ul><p>这些方法会在成功时统一触发成功消息提示。</p><h2 id="使用方式、扩展方式或注意事项" tabindex="-1">使用方式、扩展方式或注意事项 <a class="header-anchor" href="#使用方式、扩展方式或注意事项" aria-label="Permalink to &quot;使用方式、扩展方式或注意事项&quot;">​</a></h2><ul><li>需要请求加密时，在单个请求里显式传 <code>encrypt: true</code>。</li><li>分页接口建议维持后端 <code>{ code, msg, rows, total }</code> 结构，避免重复转换。</li><li>若出现 401 循环登出，优先检查后端 <code>logout</code> 接口返回是否异常。</li></ul>',22)])])}]]);export{d as __pageData,i as default};
